var channel = Channel.CreateBounded<WorkItem>(new BoundedChannelOptions(1000) {
    FullMode = BoundedChannelFullMode.Wait,
    SingleWriter = false, SingleReader = false
});

async Task ProduceAsync(ChannelWriter<WorkItem> writer, CancellationToken ct) {
    try {
        await foreach (var item in GetItemsAsync(ct))
            await writer.WriteAsync(item, ct);
    } finally { writer.Complete(); }
}

async Task ConsumeAsync(ChannelReader<WorkItem> reader, CancellationToken ct) {
    await foreach (var item in reader.ReadAllAsync(ct))
        await ProcessAsync(item, ct);
}

var producer = ProduceAsync(channel.Writer, ct);
var consumers = Enumerable.Range(0,4).Select(_ => ConsumeAsync(channel.Reader, ct));
await Task.WhenAll(Enumerable.Concat([producer], consumers));
